'use strict';

/**
* Compute the range of a one-dimensional ndarray via a callback function.
*
* @module @stdlib/stats-base-ndarray-range-by
*
* @example
* var vector = require( '@stdlib/ndarray-vector-ctor' );
* var rangeBy = require( '@stdlib/stats-base-ndarray-range-by' );
*
* function clbk( value ) {
*     return value * 2.0;
* }
*
* var x = vector( [ 1.0, 3.0, 4.0, 2.0 ], 'generic' );
*
* var v = rangeBy( [ x ], clbk );
* // returns 6.0
*/

// MODULES //

var main = require( './main.js' );


// EXPORTS //

module.exports = main;
